    .img(row3[(i1 < 64) ? i1: 63]),
    .sum_in(w2),
    .out(out[0])
);
// Col 2
pe pe3(
    .kernal(kernal[1]),
    .img(row1[(i1 < 64) ? i1: 63]),
    .sum_in(16'd0),
    .out(w3)
);

pe pe4(
    .kernal(kernal[4]),
    .img(row2[(i1 < 64) ? i1: 63]),
    .sum_in(w3),
    .out(w4)
);

pe pe5(
    .kernal(kernal[7]),
    .img(row3[(i1 < 64) ? i1: 63]),
    .sum_in(w4),
    .out(out[1])
);
// Col 3
pe pe6(
    .kernal(kernal[2]),
    .img(row1[(i1 < 64) ? i1: 63]),
    .sum_in(16'd0),
    .out(w5)
);

pe pe7(
    .kernal(kernal[5]),
    .img(row2[(i1 < 64) ? i1: 63]),
    .sum_in(w5),
    .out(w6)
);

pe pe8(
    .kernal(kernal[8]),
    .img(row3[(i1 < 64) ? i1: 63]),
    .sum_in(w6),
    .out(out[2])
);

integer j=64*3;
reg [31:0] c=0;
integer k=0;
reg [15:0] sum[0:64-3];
initial begin
    for(i=0;i<64-3+1;i=i+1) begin
        sum[i] = 16'b0;
    end
    i=0;
    convolution <= 0;
end

wire [15:0] d1,d2;
assign d1 = i1-1;
assign d2 = i1-2;
always @(posedge clk) begin
    case(state) 
        0: begin
            i <= i + 1;
            if (i >= 0 && i <= 63) row1[i] <= img[i];
            else if (i >= 64 && i <= 127) row2[i-64] <= img[i];
            else if(i >= 128 && i <= 192) row3[i-128] <= img[i];
            else begin
                state <= 1;
            end
        end
        1: begin
            i1 <= i1 + 1;

            if(i1 > 2) begin
                convolution <= sum[i1-3];
            end

            if(i1 == 0) begin
                sum[0] <= sum[0] + out[0];
            end
            else if(i1 == 1)begin
                sum[0] <= sum[0] + out[1];
                sum[1] <= sum[1] + out[0];
            end
            else if(i1 >= 2 && i1 <= 61) begin
                sum[i1-2] <= sum[i1-2] + out[2];
                sum[i1-1] <= sum[i1-1] + out[1];
                sum[i1] <= sum[i1] + out[0];
                
            end
            else if (i1 == 62) begin
                sum[60] <= sum[60] + out[2];
                sum[61] <= sum[61] + out[1];
            end
            else if (i1 == 63) begin
                sum[61] <= sum[61] + out[2];
            end
            if(i1 == 64) begin
                i1 <= 0;
                j <= j + 64;
                for(l=0; l < 62; l= l+ 1) begin
                    sum[l] <= 0;
                end  
            end
            else begin
                row1[i1] <= row2[i1];
                row2[i1] <= row3[i1];
                row3[i1] <= img[i1+j];
            end
        end
    endcase
end

endmodule


module pe (
    input [15:0]kernal,
    input [15:0]img, sum_in,
    output [15:0]out
);
    assign out = sum_in + (kernal*img);
endmodule
